// 内置工具完整 tool schema（P0 事实：来自 system-tools-overhead proxy dump 2026-05-01）
// name → JSON.stringify({name, description, input_schema})
//
// ── 排除项 ──────────────────────────────────────────────────────────────────────
// shape 工具（Agent/Bash/ScheduleWakeup）：
//   description 含运行时动态插值，无法 exact 复现，materialization=shape。
// MCP 工具（mcp__ 前缀）：
//   input_schema 由用户本地 MCP server 配置决定，不可从 JSONL/harness 静态推断。
// ToolSearch：
//   deferred tool，不在普通主请求的 tools[] 中发送，现有 fixture 无 P0 证据。
//
// ── key 顺序（P0 + sourcemap 双重确认）─────────────────────────────────────────
// 顺序与 harness assembleToolPool()（restored-src/src/tools.ts:362）一致：
//   内置工具按 name.localeCompare() 字母序，形成 tools[] 前缀段（26 个）。
//   MCP 工具紧随其后，同样字母序（不在本文件，见 MCP rules）。
// materializer 必须按此顺序生成 segment，否则：
//   (a) sourceMap 路径 reqBody.tools[i] 索引错位；
//   (b) canonical hash 因顺序不同而不匹配；
//   (c) reconciliation 产生虚假 order_mismatch finding。
// 所有已录制 fixture（2026-05-01，5 个 main_session fixture）验证：tools[] 顺序完全一致。
//
// 验证命令：bun run context:audit:fixtures（P0 dump 对账）

export const BUILTIN_TOOL_SCHEMA_JSON: Readonly<Record<string, string>> = {
  // AskUserQuestion: 4880B
  "AskUserQuestion": "{\"name\":\"AskUserQuestion\",\"description\":\"Use this tool when you need to ask the user questions during execution. This allows you to:\\n1. Gather user preferences or requirements\\n2. Clarify ambiguous instructions\\n3. Get decisions on implementation choices as you work\\n4. Offer choices to the user about what direction to take.\\n\\nUsage notes:\\n- Users will always be able to select \\\"Other\\\" to provide custom text input\\n- Use multiSelect: true to allow multiple answers to be selected for a question\\n- If you recommend a specific option, make that the first option in the list and add \\\"(Recommended)\\\" at the end of the label\\n\\nPlan mode note: In plan mode, use this tool to clarify requirements or choose between approaches BEFORE finalizing your plan. Do NOT use this tool to ask \\\"Is my plan ready?\\\" or \\\"Should I proceed?\\\" - use ExitPlanMode for plan approval. IMPORTANT: Do not reference \\\"the plan\\\" in your questions (e.g., \\\"Do you have feedback about the plan?\\\", \\\"Does the plan look good?\\\") because the user cannot see the plan in the UI until you call ExitPlanMode. If you need plan approval, use ExitPlanMode instead.\\n\\nPreview feature:\\nUse the optional `preview` field on options when presenting concrete artifacts that users need to visually compare:\\n- ASCII mockups of UI layouts or components\\n- Code snippets showing different implementations\\n- Diagram variations\\n- Configuration examples\\n\\nPreview content is rendered as markdown in a monospace box. Multi-line text with newlines is supported. When any option has a preview, the UI switches to a side-by-side layout with a vertical option list on the left and preview on the right. Do not use previews for simple preference questions where labels and descriptions suffice. Note: previews are only supported for single-select questions (not multiSelect).\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"questions\":{\"description\":\"Questions to ask the user (1-4 questions)\",\"minItems\":1,\"maxItems\":4,\"type\":\"array\",\"items\":{\"type\":\"object\",\"properties\":{\"question\":{\"description\":\"The complete question to ask the user. Should be clear, specific, and end with a question mark. Example: \\\"Which library should we use for date formatting?\\\" If multiSelect is true, phrase it accordingly, e.g. \\\"Which features do you want to enable?\\\"\",\"type\":\"string\"},\"header\":{\"description\":\"Very short label displayed as a chip/tag (max 12 chars). Examples: \\\"Auth method\\\", \\\"Library\\\", \\\"Approach\\\".\",\"type\":\"string\"},\"options\":{\"description\":\"The available choices for this question. Must have 2-4 options. Each option should be a distinct, mutually exclusive choice (unless multiSelect is enabled). There should be no 'Other' option, that will be provided automatically.\",\"minItems\":2,\"maxItems\":4,\"type\":\"array\",\"items\":{\"type\":\"object\",\"properties\":{\"label\":{\"description\":\"The display text for this option that the user will see and select. Should be concise (1-5 words) and clearly describe the choice.\",\"type\":\"string\"},\"description\":{\"description\":\"Explanation of what this option means or what will happen if chosen. Useful for providing context about trade-offs or implications.\",\"type\":\"string\"},\"preview\":{\"description\":\"Optional preview content rendered when this option is focused. Use for mockups, code snippets, or visual comparisons that help users compare options. See the tool description for the expected content format.\",\"type\":\"string\"}},\"required\":[\"label\",\"description\"],\"additionalProperties\":false}},\"multiSelect\":{\"description\":\"Set to true to allow the user to select multiple options instead of just one. Use when choices are not mutually exclusive.\",\"default\":false,\"type\":\"boolean\"}},\"required\":[\"question\",\"header\",\"options\",\"multiSelect\"],\"additionalProperties\":false}},\"answers\":{\"description\":\"User answers collected by the permission component\",\"type\":\"object\",\"propertyNames\":{\"type\":\"string\"},\"additionalProperties\":{\"type\":\"string\"}},\"annotations\":{\"description\":\"Optional per-question annotations from the user (e.g., notes on preview selections). Keyed by question text.\",\"type\":\"object\",\"propertyNames\":{\"type\":\"string\"},\"additionalProperties\":{\"type\":\"object\",\"properties\":{\"preview\":{\"description\":\"The preview content of the selected option, if the question used previews.\",\"type\":\"string\"},\"notes\":{\"description\":\"Free-text notes the user added to their selection.\",\"type\":\"string\"}},\"additionalProperties\":false}},\"metadata\":{\"description\":\"Optional metadata for tracking and analytics purposes. Not displayed to user.\",\"type\":\"object\",\"properties\":{\"source\":{\"description\":\"Optional identifier for the source of this question (e.g., \\\"remember\\\" for /remember command). Used for analytics tracking.\",\"type\":\"string\"}},\"additionalProperties\":false}},\"required\":[\"questions\"],\"additionalProperties\":false}}",

  // CronCreate: 3416B
  "CronCreate": "{\"name\":\"CronCreate\",\"description\":\"Schedule a prompt to be enqueued at a future time. Use for both recurring schedules and one-shot reminders.\\n\\nUses standard 5-field cron in the user's local timezone: minute hour day-of-month month day-of-week. \\\"0 9 * * *\\\" means 9am local \u2014 no timezone conversion needed.\\n\\n## One-shot tasks (recurring: false)\\n\\nFor \\\"remind me at X\\\" or \\\"at <time>, do Y\\\" requests \u2014 fire once then auto-delete.\\nPin minute/hour/day-of-month/month to specific values:\\n  \\\"remind me at 2:30pm today to check the deploy\\\" \u2192 cron: \\\"30 14 <today_dom> <today_month> *\\\", recurring: false\\n  \\\"tomorrow morning, run the smoke test\\\" \u2192 cron: \\\"57 8 <tomorrow_dom> <tomorrow_month> *\\\", recurring: false\\n\\n## Recurring jobs (recurring: true, the default)\\n\\nFor \\\"every N minutes\\\" / \\\"every hour\\\" / \\\"weekdays at 9am\\\" requests:\\n  \\\"*/5 * * * *\\\" (every 5 min), \\\"0 * * * *\\\" (hourly), \\\"0 9 * * 1-5\\\" (weekdays at 9am local)\\n\\n## Avoid the :00 and :30 minute marks when the task allows it\\n\\nEvery user who asks for \\\"9am\\\" gets `0 9`, and every user who asks for \\\"hourly\\\" gets `0 *` \u2014 which means requests from across the planet land on the API at the same instant. When the user's request is approximate, pick a minute that is NOT 0 or 30:\\n  \\\"every morning around 9\\\" \u2192 \\\"57 8 * * *\\\" or \\\"3 9 * * *\\\" (not \\\"0 9 * * *\\\")\\n  \\\"hourly\\\" \u2192 \\\"7 * * * *\\\" (not \\\"0 * * * *\\\")\\n  \\\"in an hour or so, remind me to...\\\" \u2192 pick whatever minute you land on, don't round\\n\\nOnly use minute 0 or 30 when the user names that exact time and clearly means it (\\\"at 9:00 sharp\\\", \\\"at half past\\\", coordinating with a meeting). When in doubt, nudge a few minutes early or late \u2014 the user will not notice, and the fleet will.\\n\\n## Session-only\\n\\nJobs live only in this Claude session \u2014 nothing is written to disk, and the job is gone when Claude exits.\\n\\n## Runtime behavior\\n\\nJobs only fire while the REPL is idle (not mid-query). The scheduler adds a small deterministic jitter on top of whatever you pick: recurring tasks fire up to 10% of their period late (max 15 min); one-shot tasks landing on :00 or :30 fire up to 90 s early. Picking an off-minute is still the bigger lever.\\n\\nRecurring tasks auto-expire after 7 days \u2014 they fire one final time, then are deleted. This bounds session lifetime. Tell the user about the 7-day limit when scheduling recurring jobs.\\n\\nReturns a job ID you can pass to CronDelete.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"cron\":{\"description\":\"Standard 5-field cron expression in local time: \\\"M H DoM Mon DoW\\\" (e.g. \\\"*/5 * * * *\\\" = every 5 minutes, \\\"30 14 28 2 *\\\" = Feb 28 at 2:30pm local once).\",\"type\":\"string\"},\"prompt\":{\"description\":\"The prompt to enqueue at each fire time.\",\"type\":\"string\"},\"recurring\":{\"description\":\"true (default) = fire on every cron match until deleted or auto-expired after 7 days. false = fire once at the next match, then auto-delete. Use false for \\\"remind me at X\\\" one-shot requests with pinned minute/hour/dom/month.\",\"type\":\"boolean\"},\"durable\":{\"description\":\"true = persist to .claude/scheduled_tasks.json and survive restarts. false (default) = in-memory only, dies when this Claude session ends. Use true only when the user asks the task to survive across sessions.\",\"type\":\"boolean\"}},\"required\":[\"cron\",\"prompt\"],\"additionalProperties\":false}}",

  // CronDelete: 360B
  "CronDelete": "{\"name\":\"CronDelete\",\"description\":\"Cancel a cron job previously scheduled with CronCreate. Removes it from the in-memory session store.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"id\":{\"description\":\"Job ID returned by CronCreate.\",\"type\":\"string\"}},\"required\":[\"id\"],\"additionalProperties\":false}}",

  // CronList: 231B
  "CronList": "{\"name\":\"CronList\",\"description\":\"List all cron jobs scheduled via CronCreate in this session.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{},\"additionalProperties\":false}}",

  // Edit: 1702B
  "Edit": "{\"name\":\"Edit\",\"description\":\"Performs exact string replacements in files.\\n\\nUsage:\\n- You must use your `Read` tool at least once in the conversation before editing. This tool will error if you attempt an edit without reading the file.\\n- When editing text from Read tool output, ensure you preserve the exact indentation (tabs/spaces) as it appears AFTER the line number prefix. The line number prefix format is: line number + tab. Everything after that is the actual file content to match. Never include any part of the line number prefix in the old_string or new_string.\\n- ALWAYS prefer editing existing files in the codebase. NEVER write new files unless explicitly required.\\n- Only use emojis if the user explicitly requests it. Avoid adding emojis to files unless asked.\\n- The edit will FAIL if `old_string` is not unique in the file. Either provide a larger string with more surrounding context to make it unique or use `replace_all` to change every instance of `old_string`.\\n- Use `replace_all` for replacing and renaming strings across the file. This parameter is useful if you want to rename a variable for instance.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"file_path\":{\"description\":\"The absolute path to the file to modify\",\"type\":\"string\"},\"old_string\":{\"description\":\"The text to replace\",\"type\":\"string\"},\"new_string\":{\"description\":\"The text to replace it with (must be different from old_string)\",\"type\":\"string\"},\"replace_all\":{\"description\":\"Replace all occurrences of old_string (default false)\",\"default\":false,\"type\":\"boolean\"}},\"required\":[\"file_path\",\"old_string\",\"new_string\"],\"additionalProperties\":false}}",

  // EnterPlanMode: 4323B
  "EnterPlanMode": "{\"name\":\"EnterPlanMode\",\"description\":\"Use this tool proactively when you're about to start a non-trivial implementation task. Getting user sign-off on your approach before writing code prevents wasted effort and ensures alignment. This tool transitions you into plan mode where you can explore the codebase and design an implementation approach for user approval.\\n\\n## When to Use This Tool\\n\\n**Prefer using EnterPlanMode** for implementation tasks unless they're simple. Use it when ANY of these conditions apply:\\n\\n1. **New Feature Implementation**: Adding meaningful new functionality\\n   - Example: \\\"Add a logout button\\\" - where should it go? What should happen on click?\\n   - Example: \\\"Add form validation\\\" - what rules? What error messages?\\n\\n2. **Multiple Valid Approaches**: The task can be solved in several different ways\\n   - Example: \\\"Add caching to the API\\\" - could use Redis, in-memory, file-based, etc.\\n   - Example: \\\"Improve performance\\\" - many optimization strategies possible\\n\\n3. **Code Modifications**: Changes that affect existing behavior or structure\\n   - Example: \\\"Update the login flow\\\" - what exactly should change?\\n   - Example: \\\"Refactor this component\\\" - what's the target architecture?\\n\\n4. **Architectural Decisions**: The task requires choosing between patterns or technologies\\n   - Example: \\\"Add real-time updates\\\" - WebSockets vs SSE vs polling\\n   - Example: \\\"Implement state management\\\" - Redux vs Context vs custom solution\\n\\n5. **Multi-File Changes**: The task will likely touch more than 2-3 files\\n   - Example: \\\"Refactor the authentication system\\\"\\n   - Example: \\\"Add a new API endpoint with tests\\\"\\n\\n6. **Unclear Requirements**: You need to explore before understanding the full scope\\n   - Example: \\\"Make the app faster\\\" - need to profile and identify bottlenecks\\n   - Example: \\\"Fix the bug in checkout\\\" - need to investigate root cause\\n\\n7. **User Preferences Matter**: The implementation could reasonably go multiple ways\\n   - If you would use AskUserQuestion to clarify the approach, use EnterPlanMode instead\\n   - Plan mode lets you explore first, then present options with context\\n\\n## When NOT to Use This Tool\\n\\nOnly skip EnterPlanMode for simple tasks:\\n- Single-line or few-line fixes (typos, obvious bugs, small tweaks)\\n- Adding a single function with clear requirements\\n- Tasks where the user has given very specific, detailed instructions\\n- Pure research/exploration tasks (use the Agent tool with explore agent instead)\\n\\n## What Happens in Plan Mode\\n\\nIn plan mode, you'll:\\n1. Thoroughly explore the codebase using Glob, Grep, and Read tools\\n2. Understand existing patterns and architecture\\n3. Design an implementation approach\\n4. Present your plan to the user for approval\\n5. Use AskUserQuestion if you need to clarify approaches\\n6. Exit plan mode with ExitPlanMode when ready to implement\\n\\n## Examples\\n\\n### GOOD - Use EnterPlanMode:\\nUser: \\\"Add user authentication to the app\\\"\\n- Requires architectural decisions (session vs JWT, where to store tokens, middleware structure)\\n\\nUser: \\\"Optimize the database queries\\\"\\n- Multiple approaches possible, need to profile first, significant impact\\n\\nUser: \\\"Implement dark mode\\\"\\n- Architectural decision on theme system, affects many components\\n\\nUser: \\\"Add a delete button to the user profile\\\"\\n- Seems simple but involves: where to place it, confirmation dialog, API call, error handling, state updates\\n\\nUser: \\\"Update the error handling in the API\\\"\\n- Affects multiple files, user should approve the approach\\n\\n### BAD - Don't use EnterPlanMode:\\nUser: \\\"Fix the typo in the README\\\"\\n- Straightforward, no planning needed\\n\\nUser: \\\"Add a console.log to debug this function\\\"\\n- Simple, obvious implementation\\n\\nUser: \\\"What files handle routing?\\\"\\n- Research task, not implementation planning\\n\\n## Important Notes\\n\\n- This tool REQUIRES user approval - they must consent to entering plan mode\\n- If unsure whether to use it, err on the side of planning - it's better to get alignment upfront than to redo work\\n- Users appreciate being consulted before significant changes are made to their codebase\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{},\"additionalProperties\":false}}",

  // EnterWorktree: 2900B
  "EnterWorktree": "{\"name\":\"EnterWorktree\",\"description\":\"Use this tool ONLY when explicitly instructed to work in a worktree \u2014 either by the user directly, or by project instructions (CLAUDE.md / memory). This tool creates an isolated git worktree and switches the current session into it.\\n\\n## When to Use\\n\\n- The user explicitly says \\\"worktree\\\" (e.g., \\\"start a worktree\\\", \\\"work in a worktree\\\", \\\"create a worktree\\\", \\\"use a worktree\\\")\\n- CLAUDE.md or memory instructions direct you to work in a worktree for the current task\\n\\n## When NOT to Use\\n\\n- The user asks to create a branch, switch branches, or work on a different branch \u2014 use git commands instead\\n- The user asks to fix a bug or work on a feature \u2014 use normal git workflow unless worktrees are explicitly requested by the user or project instructions\\n- Never use this tool unless \\\"worktree\\\" is explicitly mentioned by the user or in CLAUDE.md / memory instructions\\n\\n## Requirements\\n\\n- Must be in a git repository, OR have WorktreeCreate/WorktreeRemove hooks configured in settings.json\\n- Must not already be in a worktree\\n\\n## Behavior\\n\\n- In a git repository: creates a new git worktree inside `.claude/worktrees/` with a new branch based on HEAD\\n- Outside a git repository: delegates to WorktreeCreate/WorktreeRemove hooks for VCS-agnostic isolation\\n- Switches the session's working directory to the new worktree\\n- Use ExitWorktree to leave the worktree mid-session (keep or remove). On session exit, if still in the worktree, the user will be prompted to keep or remove it\\n\\n## Entering an existing worktree\\n\\nPass `path` instead of `name` to switch the session into a worktree that already exists (e.g., one you just created with `git worktree add`). The path must appear in `git worktree list` for the current repository \u2014 paths that are not registered worktrees of this repo are rejected. ExitWorktree will not remove a worktree entered this way; use `action: \\\"keep\\\"` to return to the original directory.\\n\\n## Parameters\\n\\n- `name` (optional): A name for a new worktree. If neither `name` nor `path` is provided, a random name is generated.\\n- `path` (optional): Path to an existing worktree of the current repository to enter instead of creating one. Mutually exclusive with `name`.\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"name\":{\"description\":\"Optional name for a new worktree. Each \\\"/\\\"-separated segment may contain only letters, digits, dots, underscores, and dashes; max 64 chars total. A random name is generated if not provided. Mutually exclusive with `path`.\",\"type\":\"string\"},\"path\":{\"description\":\"Path to an existing worktree of the current repository to switch into instead of creating a new one. Must appear in `git worktree list` for the current repo. Mutually exclusive with `name`.\",\"type\":\"string\"}},\"additionalProperties\":false}}",

  // ExitPlanMode: 2538B
  "ExitPlanMode": "{\"name\":\"ExitPlanMode\",\"description\":\"Use this tool when you are in plan mode and have finished writing your plan to the plan file and are ready for user approval.\\n\\n## How This Tool Works\\n- You should have already written your plan to the plan file specified in the plan mode system message\\n- This tool does NOT take the plan content as a parameter - it will read the plan from the file you wrote\\n- This tool simply signals that you're done planning and ready for the user to review and approve\\n- The user will see the contents of your plan file when they review it\\n\\n## When to Use This Tool\\nIMPORTANT: Only use this tool when the task requires planning the implementation steps of a task that requires writing code. For research tasks where you're gathering information, searching files, reading files or in general trying to understand the codebase - do NOT use this tool.\\n\\n## Before Using This Tool\\nEnsure your plan is complete and unambiguous:\\n- If you have unresolved questions about requirements or approach, use AskUserQuestion first (in earlier phases)\\n- Once your plan is finalized, use THIS tool to request approval\\n\\n**Important:** Do NOT use AskUserQuestion to ask \\\"Is this plan okay?\\\" or \\\"Should I proceed?\\\" - that's exactly what THIS tool does. ExitPlanMode inherently requests user approval of your plan.\\n\\n## Examples\\n\\n1. Initial task: \\\"Search for and understand the implementation of vim mode in the codebase\\\" - Do not use the exit plan mode tool because you are not planning the implementation steps of a task.\\n2. Initial task: \\\"Help me implement yank mode for vim\\\" - Use the exit plan mode tool after you have finished planning the implementation steps of the task.\\n3. Initial task: \\\"Add a new feature to handle user authentication\\\" - If unsure about auth method (OAuth, JWT, etc.), use AskUserQuestion first, then use exit plan mode tool after clarifying the approach.\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"allowedPrompts\":{\"description\":\"Prompt-based permissions needed to implement the plan. These describe categories of actions rather than specific commands.\",\"type\":\"array\",\"items\":{\"type\":\"object\",\"properties\":{\"tool\":{\"description\":\"The tool this prompt applies to\",\"type\":\"string\",\"enum\":[\"Bash\"]},\"prompt\":{\"description\":\"Semantic description of the action, e.g. \\\"run tests\\\", \\\"install dependencies\\\"\",\"type\":\"string\"}},\"required\":[\"tool\",\"prompt\"],\"additionalProperties\":false}}},\"additionalProperties\":{}}}",

  // ExitWorktree: 2505B
  "ExitWorktree": "{\"name\":\"ExitWorktree\",\"description\":\"Exit a worktree session created by EnterWorktree and return the session to the original working directory.\\n\\n## Scope\\n\\nThis tool ONLY operates on worktrees created by EnterWorktree in this session. It will NOT touch:\\n- Worktrees you created manually with `git worktree add`\\n- Worktrees from a previous session (even if created by EnterWorktree then)\\n- The directory you're in if EnterWorktree was never called\\n\\nIf called outside an EnterWorktree session, the tool is a **no-op**: it reports that no worktree session is active and takes no action. Filesystem state is unchanged.\\n\\n## When to Use\\n\\n- The user explicitly asks to \\\"exit the worktree\\\", \\\"leave the worktree\\\", \\\"go back\\\", or otherwise end the worktree session\\n- Do NOT call this proactively \u2014 only when the user asks\\n\\n## Parameters\\n\\n- `action` (required): `\\\"keep\\\"` or `\\\"remove\\\"`\\n  - `\\\"keep\\\"` \u2014 leave the worktree directory and branch intact on disk. Use this if the user wants to come back to the work later, or if there are changes to preserve.\\n  - `\\\"remove\\\"` \u2014 delete the worktree directory and its branch. Use this for a clean exit when the work is done or abandoned.\\n- `discard_changes` (optional, default false): only meaningful with `action: \\\"remove\\\"`. If the worktree has uncommitted files or commits not on the original branch, the tool will REFUSE to remove it unless this is set to `true`. If the tool returns an error listing changes, confirm with the user before re-invoking with `discard_changes: true`.\\n\\n## Behavior\\n\\n- Restores the session's working directory to where it was before EnterWorktree\\n- Clears CWD-dependent caches (system prompt sections, memory files, plans directory) so the session state reflects the original directory\\n- If a tmux session was attached to the worktree: killed on `remove`, left running on `keep` (its name is returned so the user can reattach)\\n- Once exited, EnterWorktree can be called again to create a fresh worktree\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"action\":{\"description\":\"\\\"keep\\\" leaves the worktree and branch on disk; \\\"remove\\\" deletes both.\",\"type\":\"string\",\"enum\":[\"keep\",\"remove\"]},\"discard_changes\":{\"description\":\"Required true when action is \\\"remove\\\" and the worktree has uncommitted files or unmerged commits. The tool will refuse and list them otherwise.\",\"type\":\"boolean\"}},\"required\":[\"action\"],\"additionalProperties\":false}}",

  // Monitor: 6163B
  "Monitor": "{\"name\":\"Monitor\",\"description\":\"Start a background monitor that streams events from a long-running script. Each stdout line is an event \u2014 you keep working and notifications arrive in the chat. Events arrive on their own schedule and are not replies from the user, even if one lands while you're waiting for the user to answer a question.\\n\\nPick by how many notifications you need:\\n- **One** (\\\"tell me when the server is ready / the build finishes\\\") \u2192 use **Bash with `run_in_background`** and a command that exits when the condition is true, e.g. `until grep -q \\\"Ready in\\\" dev.log; do sleep 0.5; done`. You get a single completion notification when it exits.\\n- **One per occurrence, indefinitely** (\\\"tell me every time an ERROR line appears\\\") \u2192 Monitor with an unbounded command (`tail -f`, `inotifywait -m`, `while true`).\\n- **One per occurrence, until a known end** (\\\"emit each CI step result, stop when the run completes\\\") \u2192 Monitor with a command that emits lines and then exits.\\n\\nYour script's stdout is the event stream. Each line becomes a notification. Exit ends the watch.\\n\\n  # Each matching log line is an event\\n  tail -f /var/log/app.log | grep --line-buffered \\\"ERROR\\\"\\n\\n  # Each file change is an event\\n  inotifywait -m --format '%e %f' /watched/dir\\n\\n  # Poll GitHub for new PR comments and emit one line per new comment\\n  last=$(date -u +%Y-%m-%dT%H:%M:%SZ)\\n  while true; do\\n    now=$(date -u +%Y-%m-%dT%H:%M:%SZ)\\n    gh api \\\"repos/owner/repo/issues/123/comments?since=$last\\\" --jq '.[] | \\\"\\\\(.user.login): \\\\(.body)\\\"'\\n    last=$now; sleep 30\\n  done\\n\\n  # Node script that emits events as they arrive (e.g. WebSocket listener)\\n  node watch-for-events.js\\n\\n  # Per-occurrence with a natural end: emit each CI check as it lands, exit when the run completes\\n  prev=\\\"\\\"\\n  while true; do\\n    s=$(gh pr checks 123 --json name,bucket)\\n    cur=$(jq -r '.[] | select(.bucket!=\\\"pending\\\") | \\\"\\\\(.name): \\\\(.bucket)\\\"' <<<\\\"$s\\\" | sort)\\n    comm -13 <(echo \\\"$prev\\\") <(echo \\\"$cur\\\")\\n    prev=$cur\\n    jq -e 'all(.bucket!=\\\"pending\\\")' <<<\\\"$s\\\" >/dev/null && break\\n    sleep 30\\n  done\\n\\n**Don't use an unbounded command for a single notification.** `tail -f`, `inotifywait -m`, and `while true` never exit on their own, so the monitor stays armed until timeout even after the event has fired. For \\\"tell me when X is ready,\\\" use Bash `run_in_background` with an `until` loop instead (one notification, ends in seconds). Note that `tail -f log | grep -m 1 ...` does *not* fix this: if the log goes quiet after the match, `tail` never receives SIGPIPE and the pipeline hangs anyway.\\n\\n**Script quality:**\\n- Always use `grep --line-buffered` in pipes \u2014 without it, pipe buffering delays events by minutes.\\n- In poll loops, handle transient failures (`curl ... || true`) \u2014 one failed request shouldn't kill the monitor.\\n- Poll intervals: 30s+ for remote APIs (rate limits), 0.5-1s for local checks.\\n- Write a specific `description` \u2014 it appears in every notification (\\\"errors in deploy.log\\\" not \\\"watching logs\\\").\\n- Only stdout is the event stream. Stderr goes to the output file (readable via Read) but does not trigger notifications \u2014 for a command you run directly (e.g. `python train.py 2>&1 | grep --line-buffered ...`), merge stderr with `2>&1` so its failures reach your filter. (No effect on `tail -f` of an existing log \u2014 that file only contains what its writer redirected.)\\n\\n**Coverage \u2014 silence is not success.** When watching a job or process for an outcome, your filter must match every terminal state, not just the happy path. A monitor that greps only for the success marker stays silent through a crashloop, a hung process, or an unexpected exit \u2014 and silence looks identical to \\\"still running.\\\" Before arming, ask: *if this process crashed right now, would my filter emit anything?* If not, widen it.\\n\\n  # Wrong \u2014 silent on crash, hang, or any non-success exit\\n  tail -f run.log | grep --line-buffered \\\"elapsed_steps=\\\"\\n\\n  # Right \u2014 one alternation covering progress + the failure signatures you'd act on\\n  tail -f run.log | grep -E --line-buffered \\\"elapsed_steps=|Traceback|Error|FAILED|assert|Killed|OOM\\\"\\n\\nFor poll loops checking job state, emit on every terminal status (`succeeded|failed|cancelled|timeout`), not just success. If you cannot confidently enumerate the failure signatures, broaden the grep alternation rather than narrow it \u2014 some extra noise is better than missing a crashloop.\\n\\n**Output volume**: Every stdout line is a conversation message, so the filter should be selective \u2014 but selective means \\\"the lines you'd act on,\\\" not \\\"only good news.\\\" Never pipe raw logs; use `grep --line-buffered`, `awk`, or a wrapper that emits exactly the success and failure signals you care about. Monitors that produce too many events are automatically stopped; restart with a tighter filter if this happens.\\n\\nStdout lines within 200ms are batched into a single notification, so multiline output from a single event groups naturally.\\n\\nThe script runs in the same shell environment as Bash. Exit ends the watch (exit code is reported). Timeout \u2192 killed. Set `persistent: true` for session-length watches (PR monitoring, log tails) \u2014 the monitor runs until you call TaskStop or the session ends. Use TaskStop to cancel early.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"description\":{\"description\":\"Short human-readable description of what you are monitoring (shown in notifications).\",\"type\":\"string\"},\"timeout_ms\":{\"description\":\"Kill the monitor after this deadline. Default 300000ms, max 3600000ms. Ignored when persistent is true.\",\"default\":300000,\"type\":\"number\",\"minimum\":1000},\"persistent\":{\"description\":\"Run for the lifetime of the session (no timeout). Use for session-length watches like PR monitoring or log tails. Stop with TaskStop.\",\"default\":false,\"type\":\"boolean\"},\"command\":{\"description\":\"Shell command or script. Each stdout line is an event; exit ends the watch.\",\"type\":\"string\"}},\"required\":[\"description\",\"timeout_ms\",\"persistent\",\"command\"],\"additionalProperties\":false}}",

  // NotebookEdit: 1509B
  "NotebookEdit": "{\"name\":\"NotebookEdit\",\"description\":\"Completely replaces the contents of a specific cell in a Jupyter notebook (.ipynb file) with new source. Jupyter notebooks are interactive documents that combine code, text, and visualizations, commonly used for data analysis and scientific computing. The notebook_path parameter must be an absolute path, not a relative path. The cell_number is 0-indexed. Use edit_mode=insert to add a new cell at the index specified by cell_number. Use edit_mode=delete to delete the cell at the index specified by cell_number.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"notebook_path\":{\"description\":\"The absolute path to the Jupyter notebook file to edit (must be absolute, not relative)\",\"type\":\"string\"},\"cell_id\":{\"description\":\"The ID of the cell to edit. When inserting a new cell, the new cell will be inserted after the cell with this ID, or at the beginning if not specified.\",\"type\":\"string\"},\"new_source\":{\"description\":\"The new source for the cell\",\"type\":\"string\"},\"cell_type\":{\"description\":\"The type of the cell (code or markdown). If not specified, it defaults to the current cell type. If using edit_mode=insert, this is required.\",\"type\":\"string\",\"enum\":[\"code\",\"markdown\"]},\"edit_mode\":{\"description\":\"The type of edit to make (replace, insert, delete). Defaults to replace.\",\"type\":\"string\",\"enum\":[\"replace\",\"insert\",\"delete\"]}},\"required\":[\"notebook_path\",\"new_source\"],\"additionalProperties\":false}}",

  // PushNotification: 1550B
  "PushNotification": "{\"name\":\"PushNotification\",\"description\":\"This tool sends a desktop notification in the user's terminal. If Remote Control is connected, it also pushes to their phone. Either way, it pulls their attention from whatever they're doing \u2014 a meeting, another task, dinner \u2014 to this session. That's the cost. The benefit is they learn something now that they'd want to know now: a long task finished while they were away, a build is ready, you've hit something that needs their decision before you can continue.\\n\\nBecause a notification they didn't need is annoying in a way that accumulates, err toward not sending one. Don't notify for routine progress, or to announce you've answered something they asked seconds ago and are clearly still watching, or when a quick task completes. Notify when there's a real chance they've walked away and there's something worth coming back for \u2014 or when they've explicitly asked you to notify them.\\n\\nKeep the message under 200 characters, one line, no markdown. Lead with what they'd act on \u2014 \\\"build failed: 2 auth tests\\\" tells them more than \\\"task done\\\" and more than a status dump.\\n\\nIf the result says the push wasn't sent, that's expected \u2014 no action needed.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"message\":{\"description\":\"The notification body. Keep it under 200 characters; mobile OSes truncate.\",\"type\":\"string\",\"minLength\":1},\"status\":{\"type\":\"string\",\"const\":\"proactive\"}},\"required\":[\"message\",\"status\"],\"additionalProperties\":false}}",

  // Read: 2438B
  "Read": "{\"name\":\"Read\",\"description\":\"Reads a file from the local filesystem. You can access any file directly by using this tool.\\nAssume this tool is able to read all files on the machine. If the User provides a path to a file assume that path is valid. It is okay to read a file that does not exist; an error will be returned.\\n\\nUsage:\\n- The file_path parameter must be an absolute path, not a relative path\\n- By default, it reads up to 2000 lines starting from the beginning of the file\\n- When you already know which part of the file you need, only read that part. This can be important for larger files.\\n- Results are returned using cat -n format, with line numbers starting at 1\\n- This tool allows Claude Code to read images (eg PNG, JPG, etc). When reading an image file the contents are presented visually as Claude Code is a multimodal LLM.\\n- This tool can read PDF files (.pdf). For large PDFs (more than 10 pages), you MUST provide the pages parameter to read specific page ranges (e.g., pages: \\\"1-5\\\"). Reading a large PDF without the pages parameter will fail. Maximum 20 pages per request.\\n- This tool can read Jupyter notebooks (.ipynb files) and returns all cells with their outputs, combining code, text, and visualizations.\\n- This tool can only read files, not directories. To list files in a directory, use the registered shell tool.\\n- You will regularly be asked to read screenshots. If the user provides a path to a screenshot, ALWAYS use this tool to view the file at the path. This tool will work with all temporary file paths.\\n- If you read a file that exists but has empty contents you will receive a system reminder warning in place of file contents.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"file_path\":{\"description\":\"The absolute path to the file to read\",\"type\":\"string\"},\"offset\":{\"description\":\"The line number to start reading from. Only provide if the file is too large to read at once\",\"type\":\"integer\",\"minimum\":0,\"maximum\":9007199254740991},\"limit\":{\"description\":\"The number of lines to read. Only provide if the file is too large to read at once.\",\"type\":\"integer\",\"exclusiveMinimum\":0,\"maximum\":9007199254740991},\"pages\":{\"description\":\"Page range for PDF files (e.g., \\\"1-5\\\", \\\"3\\\", \\\"10-20\\\"). Only applicable to PDF files. Maximum 20 pages per request.\",\"type\":\"string\"}},\"required\":[\"file_path\"],\"additionalProperties\":false}}",

  // RemoteTrigger: 982B
  "RemoteTrigger": "{\"name\":\"RemoteTrigger\",\"description\":\"Call the claude.ai remote-trigger API. Use this instead of curl \u2014 the OAuth token is added automatically in-process and never exposed.\\n\\nActions:\\n- list: GET /v1/code/triggers\\n- get: GET /v1/code/triggers/{trigger_id}\\n- create: POST /v1/code/triggers (requires body)\\n- update: POST /v1/code/triggers/{trigger_id} (requires body, partial update)\\n- run: POST /v1/code/triggers/{trigger_id}/run (optional body)\\n\\nThe response is the raw JSON from the API.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"action\":{\"type\":\"string\",\"enum\":[\"list\",\"get\",\"create\",\"update\",\"run\"]},\"trigger_id\":{\"description\":\"Required for get, update, and run\",\"type\":\"string\",\"pattern\":\"^[\\\\w-]+$\"},\"body\":{\"description\":\"Required for create and update; optional for run\",\"type\":\"object\",\"propertyNames\":{\"type\":\"string\"},\"additionalProperties\":{}}},\"required\":[\"action\"],\"additionalProperties\":false}}",

  // SendMessage: 2405B
  "SendMessage": "{\"name\":\"SendMessage\",\"description\":\"# SendMessage\\n\\nSend a message to another agent.\\n\\n```json\\n{\\\"to\\\": \\\"researcher\\\", \\\"summary\\\": \\\"assign task 1\\\", \\\"message\\\": \\\"start on task #1\\\"}\\n```\\n\\n| `to` | |\\n|---|---|\\n| `\\\"researcher\\\"` | Teammate by name |\\n\\nYour plain text output is NOT visible to other agents \u2014 to communicate, you MUST call this tool. Messages from teammates are delivered automatically; you don't check an inbox. Refer to teammates by name, never by UUID. When relaying, don't quote the original \u2014 it's already rendered to the user.\\n\\n## Protocol responses (legacy)\\n\\nIf you receive a JSON message with `type: \\\"shutdown_request\\\"` or `type: \\\"plan_approval_request\\\"`, respond with the matching `_response` type \u2014 echo the `request_id`, set `approve` true/false:\\n\\n```json\\n{\\\"to\\\": \\\"team-lead\\\", \\\"message\\\": {\\\"type\\\": \\\"shutdown_response\\\", \\\"request_id\\\": \\\"...\\\", \\\"approve\\\": true}}\\n{\\\"to\\\": \\\"researcher\\\", \\\"message\\\": {\\\"type\\\": \\\"plan_approval_response\\\", \\\"request_id\\\": \\\"...\\\", \\\"approve\\\": false, \\\"feedback\\\": \\\"add error handling\\\"}}\\n```\\n\\nApproving shutdown terminates your process. Rejecting plan sends the teammate back to revise. Don't originate `shutdown_request` unless asked. Don't send structured JSON status messages \u2014 use TaskUpdate.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"to\":{\"description\":\"Recipient: teammate name\",\"type\":\"string\"},\"summary\":{\"description\":\"A 5-10 word summary shown as a preview in the UI (required when message is a string)\",\"type\":\"string\"},\"message\":{\"anyOf\":[{\"description\":\"Plain text message content\",\"type\":\"string\"},{\"anyOf\":[{\"type\":\"object\",\"properties\":{\"type\":{\"type\":\"string\",\"const\":\"shutdown_request\"},\"reason\":{\"type\":\"string\"}},\"required\":[\"type\"],\"additionalProperties\":false},{\"type\":\"object\",\"properties\":{\"type\":{\"type\":\"string\",\"const\":\"shutdown_response\"},\"request_id\":{\"type\":\"string\"},\"approve\":{\"type\":\"boolean\"},\"reason\":{\"type\":\"string\"}},\"required\":[\"type\",\"request_id\",\"approve\"],\"additionalProperties\":false},{\"type\":\"object\",\"properties\":{\"type\":{\"type\":\"string\",\"const\":\"plan_approval_response\"},\"request_id\":{\"type\":\"string\"},\"approve\":{\"type\":\"boolean\"},\"feedback\":{\"type\":\"string\"}},\"required\":[\"type\",\"request_id\",\"approve\"],\"additionalProperties\":false}]}]}},\"required\":[\"to\",\"message\"],\"additionalProperties\":false}}",

  // Skill: 1713B
  "Skill": "{\"name\":\"Skill\",\"description\":\"Execute a skill within the main conversation\\n\\nWhen users ask you to perform tasks, check if any of the available skills match. Skills provide specialized capabilities and domain knowledge.\\n\\nWhen users reference a \\\"slash command\\\" or \\\"/<something>\\\", they are referring to a skill. Use this tool to invoke it.\\n\\nHow to invoke:\\n- Set `skill` to the exact name of an available skill (no leading slash). For plugin-namespaced skills use the fully qualified `plugin:skill` form.\\n- Set `args` to pass optional arguments.\\n\\nImportant:\\n- Available skills are listed in system-reminder messages in the conversation\\n- Only invoke a skill that appears in that list, or one the user explicitly typed as `/<name>` in their message. Never guess or invent a skill name from training data; otherwise do not call this tool\\n- When a skill matches the user's request, this is a BLOCKING REQUIREMENT: invoke the relevant Skill tool BEFORE generating any other response about the task\\n- NEVER mention a skill without actually calling this tool\\n- Do not invoke a skill that is already running\\n- Do not use this tool for built-in CLI commands (like /help, /clear, etc.)\\n- If you see a <command-name> tag in the current conversation turn, the skill has ALREADY been loaded - follow the instructions directly instead of calling this tool again\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"skill\":{\"description\":\"The name of a skill from the available-skills list. Do not guess names.\",\"type\":\"string\"},\"args\":{\"description\":\"Optional arguments for the skill\",\"type\":\"string\"}},\"required\":[\"skill\"],\"additionalProperties\":false}}",

  // TaskCreate: 3071B
  "TaskCreate": "{\"name\":\"TaskCreate\",\"description\":\"Use this tool to create a structured task list for your current coding session. This helps you track progress, organize complex tasks, and demonstrate thoroughness to the user.\\nIt also helps the user understand the progress of the task and overall progress of their requests.\\n\\n## When to Use This Tool\\n\\nUse this tool proactively in these scenarios:\\n\\n- Complex multi-step tasks - When a task requires 3 or more distinct steps or actions\\n- Non-trivial and complex tasks - Tasks that require careful planning or multiple operations and potentially assigned to teammates\\n- Plan mode - When using plan mode, create a task list to track the work\\n- User explicitly requests todo list - When the user directly asks you to use the todo list\\n- User provides multiple tasks - When users provide a list of things to be done (numbered or comma-separated)\\n- After receiving new instructions - Immediately capture user requirements as tasks\\n- When you start working on a task - Mark it as in_progress BEFORE beginning work\\n- After completing a task - Mark it as completed and add any new follow-up tasks discovered during implementation\\n\\n## When NOT to Use This Tool\\n\\nSkip using this tool when:\\n- There is only a single, straightforward task\\n- The task is trivial and tracking it provides no organizational benefit\\n- The task can be completed in less than 3 trivial steps\\n- The task is purely conversational or informational\\n\\nNOTE that you should not use this tool if there is only one trivial task to do. In this case you are better off just doing the task directly.\\n\\n## Task Fields\\n\\n- **subject**: A brief, actionable title in imperative form (e.g., \\\"Fix authentication bug in login flow\\\")\\n- **description**: What needs to be done\\n- **activeForm** (optional): Present continuous form shown in the spinner when the task is in_progress (e.g., \\\"Fixing authentication bug\\\"). If omitted, the spinner shows the subject instead.\\n\\nAll tasks are created with status `pending`.\\n\\n## Tips\\n\\n- Create tasks with clear, specific subjects that describe the outcome\\n- After creating tasks, use TaskUpdate to set up dependencies (blocks/blockedBy) if needed\\n- Include enough detail in the description for another agent to understand and complete the task\\n- New tasks are created with status 'pending' and no owner - use TaskUpdate with the `owner` parameter to assign them\\n- Check TaskList first to avoid creating duplicate tasks\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"subject\":{\"description\":\"A brief title for the task\",\"type\":\"string\"},\"description\":{\"description\":\"What needs to be done\",\"type\":\"string\"},\"activeForm\":{\"description\":\"Present continuous form shown in spinner when in_progress (e.g., \\\"Running tests\\\")\",\"type\":\"string\"},\"metadata\":{\"description\":\"Arbitrary metadata to attach to the task\",\"type\":\"object\",\"propertyNames\":{\"type\":\"string\"},\"additionalProperties\":{}}},\"required\":[\"subject\",\"description\"],\"additionalProperties\":false}}",

  // TaskGet: 1018B
  "TaskGet": "{\"name\":\"TaskGet\",\"description\":\"Use this tool to retrieve a task by its ID from the task list.\\n\\n## When to Use This Tool\\n\\n- When you need the full description and context before starting work on a task\\n- To understand task dependencies (what it blocks, what blocks it)\\n- After being assigned a task, to get complete requirements\\n\\n## Output\\n\\nReturns full task details:\\n- **subject**: Task title\\n- **description**: Detailed requirements and context\\n- **status**: 'pending', 'in_progress', or 'completed'\\n- **blocks**: Tasks waiting on this one to complete\\n- **blockedBy**: Tasks that must complete before this one can start\\n\\n## Tips\\n\\n- After fetching a task, verify its blockedBy list is empty before beginning work.\\n- Use TaskList to see all tasks in summary form.\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"taskId\":{\"description\":\"The ID of the task to retrieve\",\"type\":\"string\"}},\"required\":[\"taskId\"],\"additionalProperties\":false}}",

  // TaskList: 1765B
  "TaskList": "{\"name\":\"TaskList\",\"description\":\"Use this tool to list all tasks in the task list.\\n\\n## When to Use This Tool\\n\\n- To see what tasks are available to work on (status: 'pending', no owner, not blocked)\\n- To check overall progress on the project\\n- To find tasks that are blocked and need dependencies resolved\\n- Before assigning tasks to teammates, to see what's available\\n- After completing a task, to check for newly unblocked work or claim the next available task\\n- **Prefer working on tasks in ID order** (lowest ID first) when multiple tasks are available, as earlier tasks often set up context for later ones\\n\\n## Output\\n\\nReturns a summary of each task:\\n- **id**: Task identifier (use with TaskGet, TaskUpdate)\\n- **subject**: Brief description of the task\\n- **status**: 'pending', 'in_progress', or 'completed'\\n- **owner**: Agent ID if assigned, empty if available\\n- **blockedBy**: List of open task IDs that must be resolved first (tasks with blockedBy cannot be claimed until dependencies resolve)\\n\\nUse TaskGet with a specific task ID to view full details including description and comments.\\n\\n## Teammate Workflow\\n\\nWhen working as a teammate:\\n1. After completing your current task, call TaskList to find available work\\n2. Look for tasks with status 'pending', no owner, and empty blockedBy\\n3. **Prefer tasks in ID order** (lowest ID first) when multiple tasks are available, as earlier tasks often set up context for later ones\\n4. Claim an available task using TaskUpdate (set `owner` to your name), or wait for leader assignment\\n5. If blocked, focus on unblocking tasks or notify the team lead\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{},\"additionalProperties\":false}}",

  // TaskOutput: 1547B
  "TaskOutput": "{\"name\":\"TaskOutput\",\"description\":\"DEPRECATED: Background tasks return their output file path in the tool result, and you receive a <task-notification> with the same path when the task completes.\\n- For bash tasks: prefer using the Read tool on that output file path \u2014 it contains stdout/stderr.\\n- For local_agent tasks: use the Agent tool result directly. Do NOT Read the .output file \u2014 it is a symlink to the full sub-agent conversation transcript (JSONL) and will overflow your context window.\\n- For remote_agent tasks: prefer using the Read tool on the output file path \u2014 it contains the streamed remote session output (same as bash).\\n\\n- Retrieves output from a running or completed task (background shell, agent, or remote session)\\n- Takes a task_id parameter identifying the task\\n- Returns the task output along with status information\\n- Use block=true (default) to wait for task completion\\n- Use block=false for non-blocking check of current status\\n- Task IDs can be found using the /tasks command\\n- Works with all task types: background shells, async agents, and remote sessions\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"task_id\":{\"description\":\"The task ID to get output from\",\"type\":\"string\"},\"block\":{\"description\":\"Whether to wait for completion\",\"default\":true,\"type\":\"boolean\"},\"timeout\":{\"description\":\"Max wait time in ms\",\"default\":30000,\"type\":\"number\",\"minimum\":0,\"maximum\":600000}},\"required\":[\"task_id\",\"block\",\"timeout\"],\"additionalProperties\":false}}",

  // TaskStop: 537B
  "TaskStop": "{\"name\":\"TaskStop\",\"description\":\"\\n- Stops a running background task by its ID\\n- Takes a task_id parameter identifying the task to stop\\n- Returns a success or failure status\\n- Use this tool when you need to terminate a long-running task\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"task_id\":{\"description\":\"The ID of the background task to stop\",\"type\":\"string\"},\"shell_id\":{\"description\":\"Deprecated: use task_id instead\",\"type\":\"string\"}},\"additionalProperties\":false}}",

  // TaskUpdate: 3510B
  "TaskUpdate": "{\"name\":\"TaskUpdate\",\"description\":\"Use this tool to update a task in the task list.\\n\\n## When to Use This Tool\\n\\n**Mark tasks as resolved:**\\n- When you have completed the work described in a task\\n- When a task is no longer needed or has been superseded\\n- IMPORTANT: Always mark your assigned tasks as resolved when you finish them\\n- After resolving, call TaskList to find your next task\\n\\n- ONLY mark a task as completed when you have FULLY accomplished it\\n- If you encounter errors, blockers, or cannot finish, keep the task as in_progress\\n- When blocked, create a new task describing what needs to be resolved\\n- Never mark a task as completed if:\\n  - Tests are failing\\n  - Implementation is partial\\n  - You encountered unresolved errors\\n  - You couldn't find necessary files or dependencies\\n\\n**Delete tasks:**\\n- When a task is no longer relevant or was created in error\\n- Setting status to `deleted` permanently removes the task\\n\\n**Update task details:**\\n- When requirements change or become clearer\\n- When establishing dependencies between tasks\\n\\n## Fields You Can Update\\n\\n- **status**: The task status (see Status Workflow below)\\n- **subject**: Change the task title (imperative form, e.g., \\\"Run tests\\\")\\n- **description**: Change the task description\\n- **activeForm**: Present continuous form shown in spinner when in_progress (e.g., \\\"Running tests\\\")\\n- **owner**: Change the task owner (agent name)\\n- **metadata**: Merge metadata keys into the task (set a key to null to delete it)\\n- **addBlocks**: Mark tasks that cannot start until this one completes\\n- **addBlockedBy**: Mark tasks that must complete before this one can start\\n\\n## Status Workflow\\n\\nStatus progresses: `pending` \u2192 `in_progress` \u2192 `completed`\\n\\nUse `deleted` to permanently remove a task.\\n\\n## Staleness\\n\\nMake sure to read a task's latest state using `TaskGet` before updating it.\\n\\n## Examples\\n\\nMark task as in progress when starting work:\\n```json\\n{\\\"taskId\\\": \\\"1\\\", \\\"status\\\": \\\"in_progress\\\"}\\n```\\n\\nMark task as completed after finishing work:\\n```json\\n{\\\"taskId\\\": \\\"1\\\", \\\"status\\\": \\\"completed\\\"}\\n```\\n\\nDelete a task:\\n```json\\n{\\\"taskId\\\": \\\"1\\\", \\\"status\\\": \\\"deleted\\\"}\\n```\\n\\nClaim a task by setting owner:\\n```json\\n{\\\"taskId\\\": \\\"1\\\", \\\"owner\\\": \\\"my-name\\\"}\\n```\\n\\nSet up task dependencies:\\n```json\\n{\\\"taskId\\\": \\\"2\\\", \\\"addBlockedBy\\\": [\\\"1\\\"]}\\n```\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"taskId\":{\"description\":\"The ID of the task to update\",\"type\":\"string\"},\"subject\":{\"description\":\"New subject for the task\",\"type\":\"string\"},\"description\":{\"description\":\"New description for the task\",\"type\":\"string\"},\"activeForm\":{\"description\":\"Present continuous form shown in spinner when in_progress (e.g., \\\"Running tests\\\")\",\"type\":\"string\"},\"status\":{\"description\":\"New status for the task\",\"anyOf\":[{\"type\":\"string\",\"enum\":[\"pending\",\"in_progress\",\"completed\"]},{\"type\":\"string\",\"const\":\"deleted\"}]},\"addBlocks\":{\"description\":\"Task IDs that this task blocks\",\"type\":\"array\",\"items\":{\"type\":\"string\"}},\"addBlockedBy\":{\"description\":\"Task IDs that block this task\",\"type\":\"array\",\"items\":{\"type\":\"string\"}},\"owner\":{\"description\":\"New owner for the task\",\"type\":\"string\"},\"metadata\":{\"description\":\"Metadata keys to merge into the task. Set a key to null to delete it.\",\"type\":\"object\",\"propertyNames\":{\"type\":\"string\"},\"additionalProperties\":{}}},\"required\":[\"taskId\"],\"additionalProperties\":false}}",

  // TeamCreate: 7417B
  "TeamCreate": "{\"name\":\"TeamCreate\",\"description\":\"# TeamCreate\\n\\n## When to Use\\n\\nUse this tool proactively whenever:\\n- The user explicitly asks to use a team, swarm, or group of agents\\n- The user mentions wanting agents to work together, coordinate, or collaborate\\n- A task is complex enough that it would benefit from parallel work by multiple agents (e.g., building a full-stack feature with frontend and backend work, refactoring a codebase while keeping tests passing, implementing a multi-step project with research, planning, and coding phases)\\n\\nWhen in doubt about whether a task warrants a team, prefer spawning a team.\\n\\n## Choosing Agent Types for Teammates\\n\\nWhen spawning teammates via the Agent tool, choose the `subagent_type` based on what tools the agent needs for its task. Each agent type has a different set of available tools \u2014 match the agent to the work:\\n\\n- **Read-only agents** (e.g., Explore, Plan) cannot edit or write files. Only assign them research, search, or planning tasks. Never assign them implementation work.\\n- **Full-capability agents** (e.g., general-purpose) have access to all tools including file editing, writing, and bash. Use these for tasks that require making changes.\\n- **Custom agents** defined in `.claude/agents/` may have their own tool restrictions. Check their descriptions to understand what they can and cannot do.\\n\\nAlways review the agent type descriptions and their available tools listed in the Agent tool prompt before selecting a `subagent_type` for a teammate.\\n\\nCreate a new team to coordinate multiple agents working on a project. Teams have a 1:1 correspondence with task lists (Team = TaskList).\\n\\n```\\n{\\n  \\\"team_name\\\": \\\"my-project\\\",\\n  \\\"description\\\": \\\"Working on feature X\\\"\\n}\\n```\\n\\nThis creates:\\n- A team file at `~/.claude/teams/{team-name}/config.json`\\n- A corresponding task list directory at `~/.claude/tasks/{team-name}/`\\n\\n## Team Workflow\\n\\n1. **Create a team** with TeamCreate - this creates both the team and its task list\\n2. **Create tasks** using the Task tools (TaskCreate, TaskList, etc.) - they automatically use the team's task list\\n3. **Spawn teammates** using the Agent tool with `team_name` and `name` parameters to create teammates that join the team\\n4. **Assign tasks** using TaskUpdate with `owner` to give tasks to idle teammates\\n5. **Teammates work on assigned tasks** and mark them completed via TaskUpdate\\n6. **Teammates go idle between turns** - after each turn, teammates automatically go idle and send a notification. IMPORTANT: Be patient with idle teammates! Don't comment on their idleness until it actually impacts your work.\\n7. **Shutdown your team** - when the task is completed, gracefully shut down your teammates via SendMessage with `message: {type: \\\"shutdown_request\\\"}`.\\n\\n## Task Ownership\\n\\nTasks are assigned using TaskUpdate with the `owner` parameter. Any agent can set or change task ownership via TaskUpdate.\\n\\n## Automatic Message Delivery\\n\\n**IMPORTANT**: Messages from teammates are automatically delivered to you. You do NOT need to manually check your inbox.\\n\\nWhen you spawn teammates:\\n- They will send you messages when they complete tasks or need help\\n- These messages appear automatically as new conversation turns (like user messages)\\n- If you're busy (mid-turn), messages are queued and delivered when your turn ends\\n- The UI shows a brief notification with the sender's name when messages are waiting\\n\\nMessages will be delivered automatically.\\n\\nWhen reporting on teammate messages, you do NOT need to quote the original message\u2014it's already rendered to the user.\\n\\n## Teammate Idle State\\n\\nTeammates go idle after every turn\u2014this is completely normal and expected. A teammate going idle immediately after sending you a message does NOT mean they are done or unavailable. Idle simply means they are waiting for input.\\n\\n- **Idle teammates can receive messages.** Sending a message to an idle teammate wakes them up and they will process it normally.\\n- **Idle notifications are automatic.** The system sends an idle notification whenever a teammate's turn ends. You do not need to react to idle notifications unless you want to assign new work or send a follow-up message.\\n- **Do not treat idle as an error.** A teammate sending a message and then going idle is the normal flow\u2014they sent their message and are now waiting for a response.\\n- **Peer DM visibility.** When a teammate sends a DM to another teammate, a brief summary is included in their idle notification. This gives you visibility into peer collaboration without the full message content. You do not need to respond to these summaries \u2014 they are informational.\\n\\n## Discovering Team Members\\n\\nTeammates can read the team config file to discover other team members:\\n- **Team config location**: `~/.claude/teams/{team-name}/config.json`\\n\\nThe config file contains a `members` array with each teammate's:\\n- `name`: Human-readable name (**always use this** for messaging and task assignment)\\n- `agentId`: Unique identifier (for reference only - do not use for communication)\\n- `agentType`: Role/type of the agent\\n\\n**IMPORTANT**: Always refer to teammates by their NAME (e.g., \\\"team-lead\\\", \\\"researcher\\\", \\\"tester\\\"). Names are used for:\\n- `to` when sending messages\\n- Identifying task owners\\n\\nExample of reading team config:\\n```\\nUse the Read tool to read ~/.claude/teams/{team-name}/config.json\\n```\\n\\n## Task List Coordination\\n\\nTeams share a task list that all teammates can access at `~/.claude/tasks/{team-name}/`.\\n\\nTeammates should:\\n1. Check TaskList periodically, **especially after completing each task**, to find available work or see newly unblocked tasks\\n2. Claim unassigned, unblocked tasks with TaskUpdate (set `owner` to your name). **Prefer tasks in ID order** (lowest ID first) when multiple tasks are available, as earlier tasks often set up context for later ones\\n3. Create new tasks with `TaskCreate` when identifying additional work\\n4. Mark tasks as completed with `TaskUpdate` when done, then check TaskList for next work\\n5. Coordinate with other teammates by reading the task list status\\n6. If all available tasks are blocked, notify the team lead or help resolve blocking tasks\\n\\n**IMPORTANT notes for communication with your team**:\\n- Do not use terminal tools to view your team's activity; always send a message to your teammates (and remember, refer to them by name).\\n- Your team cannot hear you if you do not use the SendMessage tool. Always send a message to your teammates if you are responding to them.\\n- Do NOT send structured JSON status messages like `{\\\"type\\\":\\\"idle\\\",...}` or `{\\\"type\\\":\\\"task_completed\\\",...}`. Just communicate in plain text when you need to message teammates.\\n- Use TaskUpdate to mark tasks completed.\\n- If you are an agent in the team, the system will automatically send idle notifications to the team lead when you stop.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"team_name\":{\"description\":\"Name for the new team to create.\",\"type\":\"string\"},\"description\":{\"description\":\"Team description/purpose.\",\"type\":\"string\"},\"agent_type\":{\"description\":\"Type/role of the team lead (e.g., \\\"researcher\\\", \\\"test-runner\\\"). Used for team file and inter-agent coordination.\",\"type\":\"string\"}},\"required\":[\"team_name\"],\"additionalProperties\":false}}",

  // TeamDelete: 803B
  "TeamDelete": "{\"name\":\"TeamDelete\",\"description\":\"# TeamDelete\\n\\nRemove team and task directories when the swarm work is complete.\\n\\nThis operation:\\n- Removes the team directory (`~/.claude/teams/{team-name}/`)\\n- Removes the task directory (`~/.claude/tasks/{team-name}/`)\\n- Clears team context from the current session\\n\\n**IMPORTANT**: TeamDelete will fail if the team still has active members. Gracefully terminate teammates first, then call TeamDelete after all teammates have shut down.\\n\\nUse this when all teammates have finished their work and you want to clean up the team resources. The team name is automatically determined from the current session's team context.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{},\"additionalProperties\":false}}",

  // WebFetch: 1865B
  "WebFetch": "{\"name\":\"WebFetch\",\"description\":\"IMPORTANT: WebFetch WILL FAIL for authenticated or private URLs. Before using this tool, check if the URL points to an authenticated service (e.g. Google Docs, Confluence, Jira, GitHub). If so, look for a specialized MCP tool that provides authenticated access.\\n\\n- Fetches content from a specified URL and processes it using an AI model\\n- Takes a URL and a prompt as input\\n- Fetches the URL content, converts HTML to markdown\\n- Processes the content with the prompt using a small, fast model\\n- Returns the model's response about the content\\n- Use this tool when you need to retrieve and analyze web content\\n\\nUsage notes:\\n  - IMPORTANT: If an MCP-provided web fetch tool is available, prefer using that tool instead of this one, as it may have fewer restrictions.\\n  - The URL must be a fully-formed valid URL\\n  - HTTP URLs will be automatically upgraded to HTTPS\\n  - The prompt should describe what information you want to extract from the page\\n  - This tool is read-only and does not modify any files\\n  - Results may be summarized if the content is very large\\n  - Includes a self-cleaning 15-minute cache for faster responses when repeatedly accessing the same URL\\n  - When a URL redirects to a different host, the tool will inform you and provide the redirect URL in a special format. You should then make a new WebFetch request with the redirect URL to fetch the content.\\n  - For GitHub URLs, prefer using the gh CLI via Bash instead (e.g., gh pr view, gh issue view, gh api).\\n\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"url\":{\"description\":\"The URL to fetch content from\",\"type\":\"string\",\"format\":\"uri\"},\"prompt\":{\"description\":\"The prompt to run on the fetched content\",\"type\":\"string\"}},\"required\":[\"url\",\"prompt\"],\"additionalProperties\":false}}",

  // Write: 1022B
  "Write": "{\"name\":\"Write\",\"description\":\"Writes a file to the local filesystem.\\n\\nUsage:\\n- This tool will overwrite the existing file if there is one at the provided path.\\n- If this is an existing file, you MUST use the Read tool first to read the file's contents. This tool will fail if you did not read the file first.\\n- Prefer the Edit tool for modifying existing files \u2014 it only sends the diff. Only use this tool to create new files or for complete rewrites.\\n- NEVER create documentation files (*.md) or README files unless explicitly requested by the User.\\n- Only use emojis if the user explicitly requests it. Avoid writing emojis to files unless asked.\",\"input_schema\":{\"$schema\":\"https://json-schema.org/draft/2020-12/schema\",\"type\":\"object\",\"properties\":{\"file_path\":{\"description\":\"The absolute path to the file to write (must be absolute, not relative)\",\"type\":\"string\"},\"content\":{\"description\":\"The content to write to the file\",\"type\":\"string\"}},\"required\":[\"file_path\",\"content\"],\"additionalProperties\":false}}",

} as const;
